100→export function BrowserPanel({
101→  workspaceId,
102→  panelVisible = true,
103→  onDetach,
104→  windowLabel,
105→}: BrowserPanelProps) {
106→  // --- Initialize tabs from persisted state or create a fresh empty tab ---
107→  const [{ tabs: initialTabs, activeTabId: initialActiveId }] = useState(() =>
108→    loadWorkspaceTabs(workspaceId)
109→  );
110→  const [tabs, setTabs] = useState<BrowserTabState[]>(initialTabs);
111→  const [activeTabId, setActiveTabId] = useState<string>(initialActiveId);
112→
113→  // Imperative handles per tab
114→  const tabRefs = useRef<Map<string, BrowserTabHandle>>(new Map());
115→
116→  // Debounced persistence timer
117→  const persistTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
118→
119→  // Track previous workspaceId to detect switches
120→  const prevWorkspaceIdRef = useRef(workspaceId);
121→
122→  // Mobile viewport toggle — constrains webview width to 390px (iPhone 14 logical width)
123→  const [mobileView, setMobileView] = useState(false);
124→
125→  // Derived: active tab for nav bar state
126→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? null;
127→
128→  // --- Centralized webview visibility guard ---
129→  // Native WKWebViews render above the DOM, so CSS can't hide them.
130→  // Individual BrowserTabs manage their own show/hide via effects, but
131→  // race conditions during rapid tab switches can leave stale webviews
132→  // visible. This guard explicitly hides all non-active webviews whenever
133→  // the active tab or panel visibility changes — belt-and-suspenders.
134→  const tabInfoRef = useRef(tabs);
135→  tabInfoRef.current = tabs;
136→  const activeTabIdRef = useRef(activeTabId);
137→  activeTabIdRef.current = activeTabId;
138→
139→  useEffect(() => {
140→    const currentTabs = tabInfoRef.current;
141→    for (const tab of currentTabs) {
142→      if (tab.id !== activeTabId || !panelVisible) {
143→        native.browserViews.hide(tab.webviewLabel).catch(() => {});
144→      }
145→    }
146→  }, [activeTabId, panelVisible]);
147→
148→  // --- Persist tab state to workspace layout store (debounced) ---
149→  const persistTabs = useCallback(
150→    (currentTabs: BrowserTabState[], currentActiveId: string) => {
151→      if (!workspaceId) return;
152→
153→      if (persistTimerRef.current) clearTimeout(persistTimerRef.current);
154→      persistTimerRef.current = setTimeout(() => {
155→        workspaceLayoutActions.setLayout(workspaceId, {
156→          browserTabs: serializeTabs(currentTabs),
157→          activeBrowserTabId: currentActiveId,
158→        });
159→      }, PERSIST_DEBOUNCE_MS);
160→    },
161→    [workspaceId]
162→  );
163→
164→  // Cleanup persist timer on unmount
165→  useEffect(() => {
166→    return () => {
167→      if (persistTimerRef.current) clearTimeout(persistTimerRef.current);
168→    };
169→  }, []);
170→
171→  // --- Swap tabs when workspaceId changes (workspace switch) ---
172→  // BrowserPanel stays mounted to preserve WKWebView lifecycle, so we
173→  // manually swap tab state instead of relying on remount.
174→  //
175→  // CRITICAL: We must explicitly close old native webviews BEFORE setting
176→  // new tabs. BrowserTab's unmount cleanup also calls close, but it's async
177→  // and races with the new workspace's webviews — causing overlapping webviews
178→  // (native webviews render above the DOM so CSS can't hide them).
179→  useEffect(() => {
180→    const prevId = prevWorkspaceIdRef.current;
181→    if (prevId === workspaceId) return;
182→
183→    // Flush pending persistence for the old workspace immediately
184→    if (persistTimerRef.current) {
185→      clearTimeout(persistTimerRef.current);
186→      persistTimerRef.current = null;
187→    }
188→    // Read refs unconditionally — always fresh, no stale closure risk
189→    const currentTabs = tabInfoRef.current;
190→    const currentActiveId = activeTabIdRef.current;
191→
192→    if (prevId) {
193→      // Persist current tabs to old workspace
194→      workspaceLayoutActions.setLayout(prevId, {
195→        browserTabs: serializeTabs(currentTabs),
196→        activeBrowserTabId: currentActiveId,
197→      });
198→    }
199→
200→    // Park old views instead of destroying them — keeps native WebContentsViews
201→    // alive so they can be recalled without page reload when switching back.
202→    // Views are hidden immediately (WKWebView setHidden:YES) and stay in the
203→    // main process views Map so existing IPC handlers still work.
204→    for (const tab of currentTabs) {
205→      native.browserViews.hide(tab.webviewLabel).catch(() => {});
206→    }
207→
208→    // Load tabs for the new workspace (reuses loadWorkspaceTabs helper)
209→    const { tabs: newTabs, activeTabId: newActiveId } = loadWorkspaceTabs(workspaceId);
210→
211→    tabRefs.current.clear();
212→
213→    setTabs(newTabs);
214→    setActiveTabId(newActiveId);
215→    prevWorkspaceIdRef.current = workspaceId;
216→    // eslint-disable-next-line react-hooks/exhaustive-deps
217→  }, [workspaceId]);
218→
219→  // --- Listen for popup/OAuth new-tab requests from the main process ---
220→  // When a page calls window.open() or has target="_blank" links (e.g. Google
221→  // OAuth), the main process sends "browser:new-tab-requested" instead of
222→  // opening in the system browser. This keeps OAuth flows in-app so callbacks work.
223→  useEffect(() => {
224→    const unlisten = native.events.on(BROWSER_NEW_TAB_REQUESTED, (data) => {
225→      const newTab = createBrowserTab(workspaceId);
226→      newTab.url = data.url;
227→      newTab.currentUrl = data.url;
228→      setTabs((prev) => {
229→        const next = [...prev, newTab];
230→        persistTabs(next, newTab.id);
231→        return next;
232→      });
233→      // Only activate the new tab for foreground dispositions
234→      if (data.disposition !== "background-tab") {
235→        setActiveTabId(newTab.id);
236→      }
237→    });
238→    return unlisten;
239→  }, [workspaceId, persistTabs]);
240→
241→  // --- Tab operations ---
242→
243→  const addTab = useCallback(() => {
244→    const newTab = createBrowserTab(workspaceId);
