const handleUpdateTab = useCallback(
  (tabId: string, updates: Partial<BrowserTabState>) => {
    setTabs((prev) => {
      const next = prev.map((t) => {
        if (t.id !== tabId) return t;
        const updated = { ...t, ...updates };
