  // the active tab or panel visibility changes — belt-and-suspenders.
  const tabInfoRef = useRef(tabs);
  tabInfoRef.current = tabs;
  const activeTabIdRef = useRef(activeTabId);
  activeTabIdRef.current = activeTabId;

